{
    HAL_TIM_IRQHandler(&htim3);
}

void TIM1_BRK_UP_TRG_COM_IRQHandler(void)
{
    HAL_TIM_IRQHandler(&htim3);
}

void TIM14_IRQHandler(void)
{
    HAL_TIM_IRQHandler(&htim14);
